const body = $input.first().json.body || $input.first().json;

const o = body.onboarding || {};
const transcript = body.transcript || '';
const brand_docs = body.brand_docs || '';

const prompt = `You are Forge, an AI onboarding agent for InboundOS. Build two deliverables from the client data below.

---
CLIENT ONBOARDING DATA:
Email: ${o.email}
Offer: ${o.offer}
Ideal Client Profile: ${o.icp}
Proof / Results: ${o.proof}
Origin Story: ${o.origin_story}
Story Bank: ${o.story_bank}
Brand Voice: ${o.brand_voice}
Content Hooks: ${o.hooks}
Content History: ${o.content_history}
Competitors: ${o.competitors}
Common Objections: ${o.objections}
Delivery Process: ${o.delivery_process}
Key Differentiator: ${o.differentiator}
Off-Limits Topics: ${o.off_limits}
n8n Installed: ${o.n8n_installed}
Claude Plan: ${o.claude_plan}

---
KICKOFF CALL TRANSCRIPT:
${transcript}

---
BRAND DOCS:
${brand_docs}

---
DELIVERABLES — respond with ONLY valid JSON, no markdown, no extra text:

{
  "client_profile": {
    "name": "<infer from transcript or email>",
    "email": "<email>",
    "offer_summary": "<2-3 sentence summary of what they sell and who they sell it to>",
    "icp": "<detailed ideal client description>",
    "brand_voice": "<tone, style, words they use, words to avoid>",
    "top_hooks": ["<hook 1>", "<hook 2>", "<hook 3>"],
    "proof_points": ["<result 1>", "<result 2>", "<result 3>"],
    "objections": ["<objection 1>", "<objection 2>"],
    "differentiators": ["<differentiator 1>", "<differentiator 2>"],
    "off_limits": ["<topic 1>"],
    "content_directions": ["<content angle 1>", "<content angle 2>", "<content angle 3>"]
  },
  "kickoff_deck": {
    "audit": "<honest assessment of their current content + sales situation based on what they shared>",
    "90_day_roadmap": [
      {"week": "1-2", "focus": "<what happens>"},
      {"week": "3-4", "focus": "<what happens>"},
      {"week": "5-8", "focus": "<what happens>"},
      {"week": "9-12", "focus": "<what happens>"}
    ],
    "deliverables": [
      "<deliverable 1>",
      "<deliverable 2>",
      "<deliverable 3>",
      "<deliverable 4>"
    ],
    "expectations": {
      "from_micko": ["<what {{CLIENT_FIRST_NAME}} commits to>"],
      "from_client": ["<what client must do for this to work>"]
    },
    "first_content_ideas": [
      {"hook": "<hook>", "angle": "<angle>", "format": "<Reel/carousel/post>"},
      {"hook": "<hook>", "angle": "<angle>", "format": "<Reel/carousel/post>"},
      {"hook": "<hook>", "angle": "<angle>", "format": "<Reel/carousel/post>"}
    ]
  }
}`;

return [{ json: { prompt, email: o.email } }];

const raw = $input.first().json.output || $input.first().json.stdout || '';
const email = $('Build Prompt').first().json.email;

let parsed;
try {
  const clean = raw.replace(/```json?/gi, '').replace(/```/g, '').trim();
  parsed = JSON.parse(clean);
} catch(e) {
  parsed = { raw_output: raw, parse_error: e.message };
}

return [{
  json: {
    email,
    client_profile: parsed.client_profile || parsed,
    kickoff_deck: parsed.kickoff_deck || {}
  }
}];

